namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = "";
    public string Code { get; set; } = "";
    public string Description { get; set; } = "";
}

namespace UniversityCourseCatalog.Models;

public class Instructor
{
    public int Id { get; set; }
    public string Name { get; set; } = "";
    public string Title { get; set; } = "";
    public string Bio { get; set; } = "";
    public string Email { get; set; } = "";
    public string? ImageUrl { get; set; }
}

namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public string Code { get; set; } = "";
    public string Title { get; set; } = "";
    public string Description { get; set; } = "";
    public int Credits { get; set; }
    public string Schedule { get; set; } = "";
    public string Location { get; set; } = "";
    public int DepartmentId { get; set; }
    public Department Department { get; set; } = null!;
    public int InstructorId { get; set; }
    public Instructor Instructor { get; set; } = null!;
    public bool IsFeatured { get; set; }
    public int MaxEnrollment { get; set; }
    public int CurrentEnrollment { get; set; }
}

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    public string StudentName { get; set; } = "";
    public string StudentId { get; set; } = "";
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public interface ICatalogService
{
    IReadOnlyList<Department> GetDepartments();
    Department? GetDepartment(int id);
    IReadOnlyList<Course> GetCourses(string? searchTerm, int? departmentId, int? minCredits, int? maxCredits);
    Course? GetCourse(int id);
    IReadOnlyList<Course> GetFeaturedCourses();
    IReadOnlyList<Course> GetCoursesByDepartment(int departmentId);
    bool SubmitEnrollmentRequest(EnrollmentRequest request);
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService : ICatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Instructor> _instructors;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, data structures, and the design of computer systems." },
            new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Exploration of abstract structures, patterns, and quantitative reasoning." },
            new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Investigation of matter, energy, and the fundamental forces of nature." },
            new() { Id = 4, Name = "English", Code = "ENG", Description = "Study of literature, writing, rhetoric, and the English language." },
            new() { Id = 5, Name = "History", Code = "HIST", Description = "Examination of past events, societies, and civilizations." }
        };

        _instructors = new List<Instructor>
        {
            new() { Id = 1, Name = "Dr. Alice Chen", Title = "Professor", Bio = "Dr. Chen has over 20 years of experience in software engineering and artificial intelligence. She has published extensively in top-tier journals and holds multiple patents in machine learning.", Email = "achen@university.edu" },
            new() { Id = 2, Name = "Dr. Robert Kim", Title = "Associate Professor", Bio = "Dr. Kim specializes in algorithms and computational theory. He received his Ph.D. from MIT and has been teaching at the university for 12 years.", Email = "rkim@university.edu" },
            new() { Id = 3, Name = "Dr. Sarah Patel", Title = "Professor", Bio = "Dr. Patel is an expert in database systems and cloud computing. She previously worked at Google and Amazon before joining academia.", Email = "spatel@university.edu" },
            new() { Id = 4, Name = "Dr. James Wilson", Title = "Professor", Bio = "Dr. Wilson is a renowned mathematician whose research focuses on topology and abstract algebra. He has mentored over 30 doctoral students.", Email = "jwilson@university.edu" },
            new() { Id = 5, Name = "Dr. Maria Garcia", Title = "Associate Professor", Bio = "Dr. Garcia specializes in applied mathematics and statistics. Her work on stochastic modeling has been widely cited.", Email = "mgarcia@university.edu" },
            new() { Id = 6, Name = "Dr. David Liu", Title = "Assistant Professor", Bio = "Dr. Liu is a rising star in number theory and cryptography. He joined the faculty after completing postdoctoral work at Princeton.", Email = "dliu@university.edu" },
            new() { Id = 7, Name = "Dr. Emily Thompson", Title = "Professor", Bio = "Dr. Thompson is an experimental physicist with expertise in quantum mechanics and particle physics. She has conducted research at CERN.", Email = "ethompson@university.edu" },
            new() { Id = 8, Name = "Dr. Michael Brown", Title = "Associate Professor", Bio = "Dr. Brown focuses on astrophysics and cosmology. He leads the university observatory and has discovered several exoplanets.", Email = "mbrown@university.edu" },
            new() { Id = 9, Name = "Dr. Rachel Adams", Title = "Professor", Bio = "Dr. Adams is a celebrated author and literary critic specializing in American literature and creative writing.", Email = "radams@university.edu" },
            new() { Id = 10, Name = "Dr. Thomas Scott", Title = "Associate Professor", Bio = "Dr. Scott's research focuses on Shakespeare, Renaissance literature, and the evolution of the English language.", Email = "tscott@university.edu" },
            new() { Id = 11, Name = "Dr. Linda Martinez", Title = "Professor", Bio = "Dr. Martinez is a leading historian of the American Civil War era and Reconstruction period. She has authored five award-winning books.", Email = "lmartinez@university.edu" },
            new() { Id = 12, Name = "Dr. William Chang", Title = "Associate Professor", Bio = "Dr. Chang specializes in East Asian history and international relations. He has lived and conducted research in Japan and China for over a decade.", Email = "wchang@university.edu" },
            new() { Id = 13, Name = "Dr. Jennifer Park", Title = "Assistant Professor", Bio = "Dr. Park researches cybersecurity and distributed systems. She brings industry experience from her time at Microsoft.", Email = "jpark@university.edu" },
            new() { Id = 14, Name = "Dr. Andrew Taylor", Title = "Professor", Bio = "Dr. Taylor is an expert in thermodynamics and materials science. His research has led to breakthroughs in superconducting materials.", Email = "ataylor@university.edu" },
            new() { Id = 15, Name = "Dr. Karen White", Title = "Associate Professor", Bio = "Dr. White specializes in medieval European history and the cultural impact of the Crusades.", Email = "kwhite@university.edu" }
        };

        _courses = new List<Course>
        {
            // Computer Science
            new() { Id = 1, Code = "CS 101", Title = "Introduction to Programming", Description = "An introductory course covering fundamental programming concepts using Python. Topics include variables, control flow, functions, and basic data structures.", Credits = 3, Schedule = "MWF 9:00-9:50 AM", Location = "Science Hall 101", DepartmentId = 1, InstructorId = 1, IsFeatured = true, MaxEnrollment = 120, CurrentEnrollment = 98 },
            new() { Id = 2, Code = "CS 201", Title = "Data Structures & Algorithms", Description = "Study of fundamental data structures including arrays, linked lists, trees, graphs, and hash tables. Analysis of algorithm complexity and design techniques.", Credits = 4, Schedule = "TTh 10:30-11:50 AM", Location = "Science Hall 203", DepartmentId = 1, InstructorId = 2, IsFeatured = true, MaxEnrollment = 80, CurrentEnrollment = 72 },
            new() { Id = 3, Code = "CS 310", Title = "Database Systems", Description = "Principles of database design, relational algebra, SQL, normalization, and transaction management. Includes hands-on projects with PostgreSQL.", Credits = 3, Schedule = "MWF 1:00-1:50 PM", Location = "Science Hall 305", DepartmentId = 1, InstructorId = 3, IsFeatured = false, MaxEnrollment = 60, CurrentEnrollment = 45 },
            new() { Id = 4, Code = "CS 405", Title = "Cybersecurity Fundamentals", Description = "Introduction to cybersecurity principles including cryptography, network security, vulnerability analysis, and ethical hacking.", Credits = 3, Schedule = "TTh 2:00-3:20 PM", Location = "Tech Center 110", DepartmentId = 1, InstructorId = 13, IsFeatured = false, MaxEnrollment = 50, CurrentEnrollment = 38 },

