@page "/courses"
@using UniversityCourseCatalog.Services

@inject ICatalogService CatalogService

<PageTitle>Course Catalog</PageTitle>

<h1>Course Catalog</h1>

<div class="card mb-4">
    <div class="card-body">
        <form method="get" action="courses">
            <div class="row g-3 align-items-end">
                <div class="col-md-3">
                    <label for="search" class="form-label">Search</label>
                    <input type="text" class="form-control" id="search" name="Search" value="@Search" placeholder="Course code or title" />
                </div>
                <div class="col-md-3">
                    <label for="departmentId" class="form-label">Department</label>
                    <select class="form-select" id="departmentId" name="DepartmentId">
                        <option value="">All Departments</option>
                        @foreach (var dept in CatalogService.GetDepartments())
                        {
                            @if (DepartmentId == dept.Id)
                            {
                                <option value="@dept.Id" selected>@dept.Name</option>
                            }
                            else
                            {
                                <option value="@dept.Id">@dept.Name</option>
                            }
                        }
                    </select>
                </div>
                <div class="col-md-2">
                    <label for="minCredits" class="form-label">Min Credits</label>
                    <select class="form-select" id="minCredits" name="MinCredits">
                        <option value="">Any</option>
                        @for (int i = 1; i <= 5; i++)
                        {
                            @if (MinCredits == i)
                            {
                                <option value="@i" selected>@i</option>
                            }
                            else
                            {
                                <option value="@i">@i</option>
                            }
                        }
                    </select>
                </div>
                <div class="col-md-2">
                    <label for="maxCredits" class="form-label">Max Credits</label>
                    <select class="form-select" id="maxCredits" name="MaxCredits">
                        <option value="">Any</option>
                        @for (int i = 1; i <= 5; i++)
                        {
                            @if (MaxCredits == i)
                            {
                                <option value="@i" selected>@i</option>
                            }
                            else
                            {
                                <option value="@i">@i</option>
                            }
                        }
                    </select>
                </div>
                <div class="col-md-2">
                    <button type="submit" class="btn btn-primary w-100">Search</button>
                </div>
            </div>
            <div class="mt-2">
                <a href="courses">Clear Filters</a>
            </div>
        </form>
    </div>
</div>

@{
    var courses = CatalogService.GetCourses(Search, DepartmentId, MinCredits, MaxCredits);
}

<p class="text-muted">Showing @courses.Count course(s)</p>

@if (courses.Count == 0)
{
    <div class="alert alert-info">No courses found matching your criteria.</div>
}
else
{
    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Course Code</th>
                <th>Title</th>
                <th>Department</th>
                <th>Credits</th>
                <th>Schedule</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in courses)
            {
                <tr>
                    <td>@course.Code</td>
                    <td>@course.Title</td>
                    <td>@course.Department.Name</td>
                    <td>@course.Credits</td>
                    <td>@course.Schedule</td>
                    <td><a href="courses/@course.Id">Details</a></td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [SupplyParameterFromQuery]
    public string? Search { get; set; }

    [SupplyParameterFromQuery]
    public int? DepartmentId { get; set; }

    [SupplyParameterFromQuery]
    public int? MinCredits { get; set; }

    [SupplyParameterFromQuery]
    public int? MaxCredits { get; set; }
}

@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services

@inject ICatalogService CatalogService

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>

@if (submitted && success)
{
    <div class="alert alert-success">
        <h4 class="alert-heading">Enrollment Request Submitted!</h4>
        <p><strong>Student:</strong> @Model.StudentName</p>
        <p><strong>Student ID:</strong> @Model.StudentId</p>
        <p class="mb-0"><strong>Course:</strong> @(CatalogService.GetCourse(Model.CourseId)?.Code) - @(CatalogService.GetCourse(Model.CourseId)?.Title)</p>
    </div>
    <a href="enroll" class="btn btn-primary">Submit Another Request</a>
}
else
{
    @if (submitted && !success)
    {
        <div class="alert alert-danger">
            Enrollment request could not be processed. The course may be full or invalid.
        </div>
    }

    @if (validationErrors.Count > 0)
    {
        <div class="alert alert-danger">
            <ul class="mb-0">
                @foreach (var error in validationErrors)
                {
                    <li>@error</li>
                }
            </ul>
        </div>
    }

    <div class="card">
        <div class="card-body">
            <EditForm Model="Model" FormName="enrollment" OnSubmit="HandleSubmit">
                <AntiforgeryToken />
                <div class="mb-3">
                    <label for="studentName" class="form-label">Student Name</label>
                    <InputText id="studentName" class="form-control" @bind-Value="Model.StudentName" />
                </div>
                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID</label>
                    <InputText id="studentId" class="form-control" @bind-Value="Model.StudentId" />
                </div>
                <div class="mb-3">
                    <label for="courseId" class="form-label">Course</label>
                    <InputSelect id="courseId" class="form-select" @bind-Value="Model.CourseId">
                        <option value="0">-- Select a Course --</option>
                        @foreach (var course in CatalogService.GetCourses(null, null, null, null))
                        {
                            <option value="@course.Id">@course.Code - @course.Title</option>
                        }
                    </InputSelect>
                </div>
                <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
            </EditForm>
        </div>
    </div>
}

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest Model { get; set; } = new();

    [SupplyParameterFromQuery]
    public int? CourseId { get; set; }

    private bool submitted;
    private bool success;
    private List<string> validationErrors = new();

    protected override void OnInitialized()
    {
        if (CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        validationErrors.Clear();

        if (string.IsNullOrWhiteSpace(Model.StudentName))
            validationErrors.Add("Student Name is required.");
        if (string.IsNullOrWhiteSpace(Model.StudentId))
            validationErrors.Add("Student ID is required.");
        if (Model.CourseId <= 0)
            validationErrors.Add("Please select a course.");

        if (validationErrors.Count > 0)
            return;

        submitted = true;
        success = CatalogService.SubmitEnrollmentRequest(Model);
    }
}

