                        }
                    </InputSelect>
                </div>
                <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
            </EditForm>
        </div>
    </div>
}

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest Model { get; set; } = new();

    [SupplyParameterFromQuery]
    public int? CourseId { get; set; }

    private bool submitted;
    private bool success;
    private List<string> validationErrors = new();

    protected override void OnInitialized()
    {
        if (CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        validationErrors.Clear();

        if (string.IsNullOrWhiteSpace(Model.StudentName))
            validationErrors.Add("Student Name is required.");
        if (string.IsNullOrWhiteSpace(Model.StudentId))
            validationErrors.Add("Student ID is required.");
        if (Model.CourseId <= 0)
            validationErrors.Add("Please select a course.");

        if (validationErrors.Count > 0)
            return;

        submitted = true;
        success = CatalogService.SubmitEnrollmentRequest(Model);
    }
}

