 @if (submitted && success)
 {
     <div class="alert alert-success">
         <h4 class="alert-heading">Enrollment Request Submitted!</h4>
         <p><strong>Student:</strong> @Model.StudentName</p>
         <p><strong>Student ID:</strong> @Model.StudentId</p>
         <p class="mb-0"><strong>Course:</strong> @(CatalogService.GetCourse(Model.CourseId)?.Code) - @(CatalogService.GetCourse(Model.CourseId)?.Title)</p>
     </div>
     <a href="enroll" class="btn btn-primary">Submit Another Request</a>
 }
 else
 {
     @if (submitted && !success)
     {
         <div class="alert alert-danger">
             Enrollment request could not be processed. The course may be full or invalid.
         </div>
     }

     @if (validationErrors.Count > 0)
     {
         <div class="alert alert-danger">
             <ul class="mb-0">
                 @foreach (var error in validationErrors)
                 {
                     <li>@error</li>
                 }
             </ul>
         </div>
     }

     <div class="card">
         <div class="card-body">
             <EditForm Model="Model" FormName="enrollment" OnSubmit="HandleSubmit">
                 <AntiforgeryToken />
                 <div class="mb-3">
                     <label for="studentName" class="form-label">Student Name</label>
                     <InputText id="studentName" class="form-control" @bind-Value="Model.StudentName" />
                 </div>
                 <div class="mb-3">
                     <label for="studentId" class="form-label">Student ID</label>
                     <InputText id="studentId" class="form-control" @bind-Value="Model.StudentId" />
                 </div>
                 <div class="mb-3">
                     <label for="courseId" class="form-label">Course</label>
                     <InputSelect id="courseId" class="form-select" @bind-Value="Model.CourseId">
                         <option value="0">-- Select a Course --</option>
                         @foreach (var course in CatalogService.GetCourses(null, null, null, null))
                         {
                             <option value="@course.Id">@course.Code - @course.Title</option>
                         }
                     </InputSelect>
                 </div>
                 <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
             </EditForm>
         </div>
     </div>
 }

 @code {
     [SupplyParameterFromForm]
     private EnrollmentRequest Model { get; set; } = null!;

     protected override void OnParametersSet()
     {
         Model ??= new();
         if (CourseId.HasValue && Model.CourseId == 0)
         {
             Model.CourseId = CourseId.Value;
         }
     }

     [SupplyParameterFromQuery]
     public int? CourseId { get; set; }

     private bool submitted;
     private bool success;
     private List<string> validationErrors = new();

     private void HandleSubmit()
     {
         validationErrors.Clear();

         if (string.IsNullOrWhiteSpace(Model.StudentName))
             validationErrors.Add("Student Name is required.");
         if (string.IsNullOrWhiteSpace(Model.StudentId))
             validationErrors.Add("Student ID is required.");
         if (Model.CourseId <= 0)
             validationErrors.Add("Please select a course.");

         if (validationErrors.Count > 0)
             return;

         submitted = true;
         success = CatalogService.SubmitEnrollmentRequest(Model);
     }
 }

