84.     {
85.         var query = _courses.AsEnumerable();
86. 
87.         if (!string.IsNullOrWhiteSpace(searchTerm))
88.         {
89.             var term = searchTerm.Trim();
90.             query = query.Where(c =>
91.                 c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
92.                 c.Title.Contains(term, StringComparison.OrdinalIgnoreCase));
93.         }
94. 
95.         if (departmentId.HasValue)
96.             query = query.Where(c => c.DepartmentId == departmentId.Value);
97. 
98.         if (minCredits.HasValue)
99.             query = query.Where(c => c.Credits >= minCredits.Value);
100. 
101.         if (maxCredits.HasValue)
102.             query = query.Where(c => c.Credits <= maxCredits.Value);
103. 
104.         return query.ToList().AsReadOnly();
105.     }
106. 
107.     public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);
108. 
