110. 
111.     public IReadOnlyList<Course> GetCoursesByDepartment(int departmentId) =>
112.         _courses.Where(c => c.DepartmentId == departmentId).ToList().AsReadOnly();
113. 
114.     public bool SubmitEnrollmentRequest(EnrollmentRequest request)
115.     {
116.         if (string.IsNullOrWhiteSpace(request.StudentName) ||
117.             string.IsNullOrWhiteSpace(request.StudentId) ||
118.             request.CourseId <= 0)
119.             return false;
120. 
121.         var course = GetCourse(request.CourseId);
122.         if (course == null || course.CurrentEnrollment >= course.MaxEnrollment)
123.             return false;
124. 
125.         course.CurrentEnrollment++;
126.         return true;
127.     }
128. }
