     public IReadOnlyList<Course> GetCoursesByDepartment(int departmentId) =>
         _courses.Where(c => c.DepartmentId == departmentId).ToList().AsReadOnly();

     public bool SubmitEnrollmentRequest(EnrollmentRequest request)
     {
         if (string.IsNullOrWhiteSpace(request.StudentName) ||
             string.IsNullOrWhiteSpace(request.StudentId) ||
             request.CourseId <= 0)
             return false;

         var course = GetCourse(request.CourseId);
         if (course == null || course.CurrentEnrollment >= course.MaxEnrollment)
             return false;

         course.CurrentEnrollment++;
         return true;
     }
 }

